import{_ as r,o as i,c as t,a4 as o}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"生物知识速查卡","description":"","frontmatter":{},"headers":[],"relativePath":"biology/quickref.md","filePath":"biology/quickref.md"}'),a={name:"biology/quickref.md"};function n(s,l,e,g,h,u){return i(),t("div",null,[...l[0]||(l[0]=[o('<h1 id="生物知识速查卡" tabindex="-1">生物知识速查卡 <a class="header-anchor" href="#生物知识速查卡" aria-label="Permalink to &quot;生物知识速查卡&quot;">​</a></h1><p><strong>考前30分钟快速浏览——核心概念与结论</strong></p><hr><h2 id="一、分子与细胞" tabindex="-1">一、分子与细胞 <a class="header-anchor" href="#一、分子与细胞" aria-label="Permalink to &quot;一、分子与细胞&quot;">​</a></h2><h3 id="细胞的分子组成" tabindex="-1">细胞的分子组成 <a class="header-anchor" href="#细胞的分子组成" aria-label="Permalink to &quot;细胞的分子组成&quot;">​</a></h3><ul><li><strong>最基本元素</strong>：C</li><li><strong>主要能源物质</strong>：糖类</li><li><strong>储能物质</strong>：脂肪</li><li><strong>生命活动的主要承担者</strong>：蛋白质</li><li><strong>遗传信息的携带者</strong>：核酸</li></ul><h3 id="蛋白质" tabindex="-1">蛋白质 <a class="header-anchor" href="#蛋白质" aria-label="Permalink to &quot;蛋白质&quot;">​</a></h3><ul><li><strong>基本单位</strong>：氨基酸（20种）</li><li><strong>肽键数</strong> = 氨基酸数 - 肽链数</li><li><strong>结构层次</strong>：氨基酸→多肽链→蛋白质</li><li><strong>功能</strong>：结构蛋白、酶、抗体、载体、激素</li></ul><h3 id="核酸" tabindex="-1">核酸 <a class="header-anchor" href="#核酸" aria-label="Permalink to &quot;核酸&quot;">​</a></h3><ul><li><strong>DNA</strong>：双螺旋，A-T、G-C配对</li><li><strong>RNA</strong>：单链，A-U、G-C配对</li></ul><h3 id="细胞膜" tabindex="-1">细胞膜 <a class="header-anchor" href="#细胞膜" aria-label="Permalink to &quot;细胞膜&quot;">​</a></h3><ul><li><strong>结构</strong>：流动镶嵌模型</li><li><strong>结构特点</strong>：流动性</li><li><strong>功能特性</strong>：选择透过性</li><li><strong>运输方式</strong>：自由扩散、协助扩散、主动运输、胞吞胞吐</li></ul><h3 id="细胞器" tabindex="-1">细胞器 <a class="header-anchor" href="#细胞器" aria-label="Permalink to &quot;细胞器&quot;">​</a></h3><ul><li><strong>线粒体</strong>：有氧呼吸主要场所</li><li><strong>叶绿体</strong>：光合作用场所</li><li><strong>核糖体</strong>：蛋白质合成</li><li><strong>内质网</strong>：蛋白质加工、脂质合成</li><li><strong>高尔基体</strong>：蛋白质加工、分类、包装</li><li><strong>溶酶体</strong>：含水解酶，分解衰老细胞器</li></ul><h3 id="细胞代谢" tabindex="-1">细胞代谢 <a class="header-anchor" href="#细胞代谢" aria-label="Permalink to &quot;细胞代谢&quot;">​</a></h3><p><strong>酶</strong>：</p><ul><li>本质：大多数是蛋白质，少数是RNA</li><li>特性：高效性、专一性、作用条件温和</li><li>影响因素：温度、pH</li></ul><p><strong>ATP</strong>：</p><ul><li>结构：腺苷 + 三个磷酸基团</li><li>功能：直接能源物质</li><li>ATP ⇌ ADP + Pi + 能量</li></ul><p><strong>有氧呼吸</strong>：</p><ul><li>第一阶段：细胞质基质，葡萄糖→丙酮酸 + [H]，少量ATP</li><li>第二阶段：线粒体基质，丙酮酸 + H₂O → CO₂ + [H]，少量ATP</li><li>第三阶段：线粒体内膜，[H] + O₂ → H₂O，大量ATP</li></ul><p><strong>无氧呼吸</strong>：</p><ul><li>酒精发酵：C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂ + 少量能量</li><li>乳酸发酵：C₆H₁₂O₆ → 2C₃H₆O₃ + 少量能量</li></ul><p><strong>光合作用</strong>：</p><ul><li>光反应（类囊体薄膜）：H₂O → [H] + O₂，ADP + Pi → ATP</li><li>暗反应（叶绿体基质）：CO₂ + C₅ → 2C₃，2C₃ + [H] + ATP → (CH₂O) + C₅</li></ul><p><strong>关系</strong>：总光合速率 = 净光合速率 + 呼吸速率</p><h3 id="细胞生命历程" tabindex="-1">细胞生命历程 <a class="header-anchor" href="#细胞生命历程" aria-label="Permalink to &quot;细胞生命历程&quot;">​</a></h3><ul><li><strong>有丝分裂</strong>：间期→前期→中期→后期→末期</li><li><strong>分化实质</strong>：基因的选择性表达</li><li><strong>细胞全能性</strong>：已分化细胞仍具有发育成完整个体的潜能</li><li><strong>衰老特征</strong>：水分减少、酶活性降低、色素积累</li><li><strong>凋亡</strong>：基因决定的细胞编程性死亡</li><li><strong>癌变</strong>：原癌基因和抑癌基因突变</li></ul><hr><h2 id="二、遗传与进化" tabindex="-1">二、遗传与进化 <a class="header-anchor" href="#二、遗传与进化" aria-label="Permalink to &quot;二、遗传与进化&quot;">​</a></h2><h3 id="减数分裂" tabindex="-1">减数分裂 <a class="header-anchor" href="#减数分裂" aria-label="Permalink to &quot;减数分裂&quot;">​</a></h3><ul><li><strong>减Ⅰ</strong>：同源染色体分离，染色体数目减半</li><li><strong>减Ⅱ</strong>：着丝点分裂，姐妹染色单体分开</li><li><strong>结果</strong>：4个生殖细胞，染色体数目减半</li></ul><h3 id="dna结构" tabindex="-1">DNA结构 <a class="header-anchor" href="#dna结构" aria-label="Permalink to &quot;DNA结构&quot;">​</a></h3><ul><li><strong>双螺旋</strong>：反向平行</li><li><strong>外侧</strong>：磷酸-脱氧核糖骨架</li><li><strong>内侧</strong>：碱基对（A=T，G≡C）</li></ul><h3 id="dna复制" tabindex="-1">DNA复制 <a class="header-anchor" href="#dna复制" aria-label="Permalink to &quot;DNA复制&quot;">​</a></h3><ul><li><strong>时间</strong>：间期</li><li><strong>方式</strong>：半保留复制</li><li><strong>条件</strong>：模板、原料、能量、酶</li></ul><h3 id="基因表达" tabindex="-1">基因表达 <a class="header-anchor" href="#基因表达" aria-label="Permalink to &quot;基因表达&quot;">​</a></h3><ul><li><strong>转录</strong>：DNA → mRNA（A-U、T-A、G-C、C-G）</li><li><strong>翻译</strong>：mRNA → 蛋白质（密码子、反密码子）</li><li><strong>数量关系</strong>：DNA碱基数 : mRNA碱基数 : 氨基酸数 = 6:3:1</li></ul><h3 id="遗传规律" tabindex="-1">遗传规律 <a class="header-anchor" href="#遗传规律" aria-label="Permalink to &quot;遗传规律&quot;">​</a></h3><ul><li><strong>分离定律</strong>：等位基因随同源染色体分离而分离</li><li><strong>自由组合定律</strong>：非同源染色体上的非等位基因自由组合</li><li><strong>分离比</strong>：3:1（自交）、1:1（测交）、9:3:3:1（双杂合自交）</li></ul><h3 id="伴性遗传" tabindex="-1">伴性遗传 <a class="header-anchor" href="#伴性遗传" aria-label="Permalink to &quot;伴性遗传&quot;">​</a></h3><ul><li><strong>X隐性</strong>：男患者多于女患者，交叉遗传（如色盲、血友病）</li><li><strong>X显性</strong>：女患者多于男患者（如抗维生素D佝偻病）</li></ul><h3 id="变异" tabindex="-1">变异 <a class="header-anchor" href="#变异" aria-label="Permalink to &quot;变异&quot;">​</a></h3><ul><li><strong>基因突变</strong>：DNA分子中碱基对的替换、增添、缺失</li><li><strong>基因重组</strong>：减Ⅰ后期自由组合、前期交叉互换</li><li><strong>染色体变异</strong>：结构变异、数目变异</li></ul><h3 id="进化" tabindex="-1">进化 <a class="header-anchor" href="#进化" aria-label="Permalink to &quot;进化&quot;">​</a></h3><ul><li><strong>基本单位</strong>：种群</li><li><strong>原材料</strong>：突变和基因重组</li><li><strong>方向决定</strong>：自然选择</li><li><strong>新物种形成</strong>：隔离</li></ul><hr><h2 id="三、稳态与调节" tabindex="-1">三、稳态与调节 <a class="header-anchor" href="#三、稳态与调节" aria-label="Permalink to &quot;三、稳态与调节&quot;">​</a></h2><h3 id="神经调节" tabindex="-1">神经调节 <a class="header-anchor" href="#神经调节" aria-label="Permalink to &quot;神经调节&quot;">​</a></h3><ul><li><strong>结构基础</strong>：反射弧（感受器→传入神经→神经中枢→传出神经→效应器）</li><li><strong>兴奋传导</strong>：静息电位（外正内负，K⁺外流）→动作电位（外负内正，Na⁺内流）</li><li><strong>突触传递</strong>：电信号→化学信号（神经递质）→电信号，单向传递</li></ul><h3 id="体液调节" tabindex="-1">体液调节 <a class="header-anchor" href="#体液调节" aria-label="Permalink to &quot;体液调节&quot;">​</a></h3><ul><li><strong>激素特点</strong>：微量高效、体液运输、作用于靶器官靶细胞</li><li><strong>甲状腺激素</strong>：促进新陈代谢和生长发育</li><li><strong>胰岛素</strong>：降低血糖</li><li><strong>胰高血糖素</strong>：升高血糖</li><li><strong>分级调节</strong>：下丘脑→垂体→甲状腺</li></ul><h3 id="血糖调节" tabindex="-1">血糖调节 <a class="header-anchor" href="#血糖调节" aria-label="Permalink to &quot;血糖调节&quot;">​</a></h3><ul><li><strong>升高→胰岛素分泌→降血糖</strong></li><li><strong>降低→胰高血糖素分泌→升血糖</strong></li><li><strong>关系</strong>：拮抗作用、反馈调节</li></ul><h3 id="免疫调节" tabindex="-1">免疫调节 <a class="header-anchor" href="#免疫调节" aria-label="Permalink to &quot;免疫调节&quot;">​</a></h3><ul><li><strong>三道防线</strong>：皮肤黏膜（第一道）、体液中的杀菌物质和吞噬细胞（第二道）、免疫器官和免疫细胞（第三道）</li><li><strong>特异性免疫</strong>： <ul><li>体液免疫：B细胞→浆细胞→抗体，对付细胞外病原体</li><li>细胞免疫：T细胞→效应T细胞，对付细胞内病原体</li></ul></li><li><strong>记忆细胞</strong>：快速二次免疫</li></ul><h3 id="植物激素" tabindex="-1">植物激素 <a class="header-anchor" href="#植物激素" aria-label="Permalink to &quot;植物激素&quot;">​</a></h3><ul><li><strong>生长素</strong>：两重性（低促高抑），极性运输</li><li><strong>赤霉素</strong>：促进细胞伸长</li><li><strong>细胞分裂素</strong>：促进细胞分裂</li><li><strong>脱落酸</strong>：抑制生长，促进脱落</li><li><strong>乙烯</strong>：促进果实成熟</li></ul><hr><h2 id="四、生态与环境" tabindex="-1">四、生态与环境 <a class="header-anchor" href="#四、生态与环境" aria-label="Permalink to &quot;四、生态与环境&quot;">​</a></h2><h3 id="种群" tabindex="-1">种群 <a class="header-anchor" href="#种群" aria-label="Permalink to &quot;种群&quot;">​</a></h3><ul><li><strong>数量特征</strong>：种群密度（最基本）、出生率、死亡率、迁入率、迁出率、年龄组成、性别比例</li><li><strong>J型曲线</strong>：理想条件，Nt = N₀λᵗ</li><li><strong>S型曲线</strong>：有限环境，K值（环境容纳量），K/2时增长速率最快</li></ul><h3 id="群落" tabindex="-1">群落 <a class="header-anchor" href="#群落" aria-label="Permalink to &quot;群落&quot;">​</a></h3><ul><li><strong>种间关系</strong>：互利共生、捕食、竞争、寄生</li><li><strong>空间结构</strong>：垂直结构（分层）、水平结构（镶嵌）</li><li><strong>演替</strong>：初生演替、次生演替</li></ul><h3 id="生态系统" tabindex="-1">生态系统 <a class="header-anchor" href="#生态系统" aria-label="Permalink to &quot;生态系统&quot;">​</a></h3><ul><li><strong>组成</strong>：非生物物质和能量、生产者、消费者、分解者</li><li><strong>能量流动</strong>：单向流动、逐级递减（10%-20%）</li><li><strong>物质循环</strong>：碳循环（CO₂形式）、氮循环</li><li><strong>稳定性</strong>：抵抗力稳定性、恢复力稳定性（一般负相关）</li></ul><h3 id="生物多样性" tabindex="-1">生物多样性 <a class="header-anchor" href="#生物多样性" aria-label="Permalink to &quot;生物多样性&quot;">​</a></h3><ul><li><strong>三个层次</strong>：基因多样性、物种多样性、生态系统多样性</li><li><strong>保护措施</strong>：就地保护（最有效）、易地保护</li></ul><hr><h2 id="五、生物技术" tabindex="-1">五、生物技术 <a class="header-anchor" href="#五、生物技术" aria-label="Permalink to &quot;五、生物技术&quot;">​</a></h2><h3 id="基因工程" tabindex="-1">基因工程 <a class="header-anchor" href="#基因工程" aria-label="Permalink to &quot;基因工程&quot;">​</a></h3><ul><li><strong>工具</strong>：限制酶（切割）、DNA连接酶（连接）、载体（运输）</li><li><strong>四步骤</strong>：获取目的基因→构建表达载体→导入受体细胞→检测与鉴定</li><li><strong>PCR</strong>：变性→复性→延伸，指数扩增</li><li><strong>应用</strong>：转基因作物、基因药物、基因治疗</li></ul><h3 id="植物细胞工程" tabindex="-1">植物细胞工程 <a class="header-anchor" href="#植物细胞工程" aria-label="Permalink to &quot;植物细胞工程&quot;">​</a></h3><ul><li><strong>组织培养原理</strong>：植物细胞全能性</li><li><strong>过程</strong>：外植体→愈伤组织→胚状体→植株</li><li><strong>体细胞杂交</strong>：克服远缘杂交不亲和</li></ul><h3 id="动物细胞工程" tabindex="-1">动物细胞工程 <a class="header-anchor" href="#动物细胞工程" aria-label="Permalink to &quot;动物细胞工程&quot;">​</a></h3><ul><li><strong>细胞培养</strong>：原代培养、传代培养</li><li><strong>核移植</strong>：克隆</li><li><strong>细胞融合</strong>：单克隆抗体制备</li></ul><h3 id="单克隆抗体" tabindex="-1">单克隆抗体 <a class="header-anchor" href="#单克隆抗体" aria-label="Permalink to &quot;单克隆抗体&quot;">​</a></h3><ul><li><strong>优点</strong>：特异性强、灵敏度高、可大量制备</li><li><strong>应用</strong>：诊断试剂、治疗疾病、生物导弹</li></ul><h3 id="胚胎工程" tabindex="-1">胚胎工程 <a class="header-anchor" href="#胚胎工程" aria-label="Permalink to &quot;胚胎工程&quot;">​</a></h3><ul><li><strong>胚胎移植</strong>：最后一道工序</li><li><strong>胚胎分割</strong>：无性繁殖，内细胞团均等分割</li></ul><h3 id="发酵工程" tabindex="-1">发酵工程 <a class="header-anchor" href="#发酵工程" aria-label="Permalink to &quot;发酵工程&quot;">​</a></h3><ul><li><strong>影响因素</strong>：温度、pH、溶氧量</li><li><strong>应用</strong>：食品（酒、醋、酸奶）、药物（抗生素、维生素）</li></ul><hr><h2 id="六、高频易错点" tabindex="-1">六、高频易错点 <a class="header-anchor" href="#六、高频易错点" aria-label="Permalink to &quot;六、高频易错点&quot;">​</a></h2><ol><li><strong>酶可以重复利用</strong>，在反应前后性质不变</li><li><strong>光合作用产生的ATP仅供暗反应使用</strong>，不用于其他生命活动</li><li><strong>有氧呼吸产生的CO₂中的O来自葡萄糖和水</strong>，不是来自O₂</li><li><strong>DNA复制是半保留</strong>，不是全保留也不是分散</li><li><strong>密码子在mRNA上</strong>，反密码子在tRNA上</li><li><strong>生长素的两重性</strong>：低浓度促进，高浓度抑制</li><li><strong>能量流动是单向的</strong>，不能循环利用</li><li><strong>抗体由浆细胞产生</strong>，不是由T细胞产生</li></ol><hr><p><strong>文档编号</strong>: Bio-Review-Tool-002<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>',87)])])}const b=r(a,[["render",n]]);export{c as __pageData,b as default};
